-- Création de la table (schéma Murex)
DROP TABLE IF EXISTS trades;

CREATE TABLE trades (
    trade_id        VARCHAR(20)     NOT NULL,
    counterparty_id VARCHAR(10)     NOT NULL,
    trade_date      VARCHAR(20),
    settlement_date VARCHAR(20),
    asset_class     VARCHAR(30),
    notional_eur    DECIMAL(18, 2),
    price           DECIMAL(18, 6),
    quantity        INTEGER,
    default_flag    TINYINT,
    trader_id       VARCHAR(10)
);

-- Index sur clé primaire
CREATE INDEX idx_trade_id ON trades(trade_id);
CREATE INDEX idx_trade_date ON trades(trade_date);
CREATE INDEX idx_counterparty ON trades(counterparty_id);

